'use strict'
var burgerBox = document.querySelector('.burger__btn-box'),
	burgerBtn = document.querySelector('.burger__btn'),
	barsBtn = document.querySelector('.burger__btn-bars'),
	closeBtn = document.querySelector('.close__btn'),
	nav = document.querySelector('.nav'),
	navBox = document.querySelector('.nav__box'),
	navLink = document.querySelectorAll('.nav__box-link'),
	allSections = document.querySelectorAll('section'),
	aboutusSection = document.querySelector('.aboutus'),
	summarySection = document.querySelector('.summary'),
	summaryIcon = document.querySelector('.fa-angle-down'),
	contactSection = document.querySelector('.contact'),
	footerYear = document.querySelector('.footer__year'),
	getYear = function () {
		var e = new Date().getFullYear()
		footerYear.textContent = e
	},
	handleObserver = function () {
		var t = window.scrollY,
			o = document.querySelector('.aboutus-n')
		allSections.forEach(function (e) {
			e.classList.contains('aboutus') && e.offsetTop <= t + 140
				? ((o.style.backgroundColor = '$main-color'), (o.style.color = '$secondary-color'))
				: e.classList.contains('offers') && e.offsetTop
		})
	},
	showList = function (e, t) {
		;(e = document.getElementById(e)), (t = document.getElementsByClassName(t))
		e.classList.toggle('show-list'), t[0].classList.toggle('rotate-arrow')
	},
	showNav = function () {
		nav.classList.add('nav--active'), closeBtn.classList.add('show-btn'), barsBtn.classList.remove('burger__btn-bars')
	},
	hideNav = function () {
		nav.classList.remove('nav--active'),
			barsBtn.classList.add('burger__btn-bars'),
			closeBtn.classList.remove('show-btn')
	},
	checkClick = function (e) {
		e.target.classList.contains('nav--active') || hideNav()
	}
getYear(),
	window.addEventListener('scroll', handleObserver),
	closeBtn.addEventListener('click', hideNav),
	burgerBtn.addEventListener('click', showNav),
	navLink.forEach(function (e) {
		e.addEventListener('click', hideNav)
	})
